//-------------------------------------------------------------------------
// function name : f_FieldClear
// function desc : 조회 필드 Clear
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {

    $c.gus.cfInitObjects(tbl_search, [ed_acqDtEndDt, ed_acqDtStDt, ica_procDt]);
    scwin.f_SetSrchDefault();
}

//-------------------------------------------------------------------------
// function name : f_SetSrchDefault
// function desc : 조회 기본값 설정
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function () {

    ed_acqDtStDt.setValue(WebSquare.date.getCurrentServerDate().substring(0, 6) + "01");
    ed_acqDtEndDt.setValue(WebSquare.date.getCurrentServerDate());
    ica_procDt.setValue(WebSquare.date.getCurrentServerDate());
    acb_stockAsetYn.setSelectedIndex(1);
    acb_asetPatternCd.setSelectedIndex(6);
    $c.gus.cfDisableObjects([acb_asetPatternCd]);
    ed_acqDtStDt.focus();
}

//-------------------------------------------------------------------------
// function name : f_setCompanyInfo
// function desc : 자회사 회계 시스템 추가에 따른 설정
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {

    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
}

//-------------------------------------------------------------------------
// function name : f_PopUpCompanyInfo
// function desc : 회사 입력 팝업
// function Parameter : pWinCloseTF : 팝업창 여부 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {

    var rtnList = udc_companyInfo.cfCommonPopUp(scwin.udc_companyInfo_callBackFunc
        , ed_coCd.getValue(), ed_coNm.getValue()
        , pWinCloseTF, null, null, null, null
        , null, null, null, null, null);

}

scwin.udc_companyInfo_callBackFunc = function (rtnList) {

    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);
        ed_coNm.setValue(rtnList[5]);
        ed_coCd.options.hidVal = rtnList[0];
        scwin.txtCoClsCd = rtnList[1];
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if (scwin.isFirst == true) {
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }

        scwin.isFirst = false;
    }
};

//-------------------------------------------------------------------------
// function name : f_IsPopUp
// function desc : 팝업 여부 검사
// function Parameter : inObj : 오브젝트명 
//-------------------------------------------------------------------------
scwin.f_IsPopUp = function (inObj) {

    var inValue = scwin.f_GetObjValue(inObj);
    var hidValue = inObj.options.hidVal;

    if ($c.gus.cfIsNull(inValue)) {
        inObj.hidVal = "";
        for (var i = 1; i < f_IsPopUp.arguments.length; i++) {
            f_SetObjValue(f_IsPopUp.arguments[i], "");
        }
        return false;
    }
    if (inValue == hidValue) return false;

    return true;
}

scwin.udc_dept_onblurCodeEvent = function (e) {
    if (ed_srchAcctDeptCd.getValue() != "") {
        scwin.f_deptPopUp();
    }
    else {
        ed_srchAcctDeptNm.setValue("");
    }
};

