scwin.ica_procDt_onviewchange = async function (info) {
    if (ds_master.getTotalRow() > 0) {
        await $c.gus.cfAlertMsg("전환일자가 변경되어 재조회 됩니다.");
        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    ds_saveList.removeAll();
    var nRow = 0;
    for (let i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getCellData(i, "procYn") == "1") {
            ds_saveList.setRowArray(i, ds_master.getRowArray(i));
            ds_saveList.setCellData(i, "stockDt", ica_procDt.getValue());
            nRow = nRow + 1;
        }
    }



    if (nRow <= 0) {
        await $c.gus.cfAlertMsg("선택한 내역이 존재하지 않습니다.");
        return;
    }

    // 처리일자 입력 validation
    if (!$c.gus.cfValidate([ica_procDt]))
        return;

    // 자산 입력 validation
    if (!await scwin.f_ValidateAset())
        return;

    if (await $c.win.confirm(MSG_CM_CRM_001)) {

        // tr_master.Parameters = "stockDt=" + ica_procDt.getValue();
        dma_stockDt.set("stockDt", ica_procDt.getValue());
        $c.sbm.execute(sbm_master);
    }
}

//-------------------------------------------------------------------------
// function name : f_ValidateAset
// function desc : 자산입력 validation
// function Parameter : null 
//-------------------------------------------------------------------------
scwin.f_ValidateAset = async function () {


    for (var i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getCellData(i, "procYn") == 1 || ds_master.getRowStatus(i) == "U") {
            if (ds_master.getCellData(i, "procQty") <= 0) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["매각수량"]);
                // ds_master.RowPosition = i;
                // gr_master.SetColumn("procQty");
                return false;
            }

            if (ds_master.getCellData(i, "procQty") > ds_master.getCellData(i, "qty")) {
                await $c.gus.cfAlertMsg("매각수량이 수량을 초과하였습니다.");
                // ds_master.RowPosition = i;
                // gr_master.SetColumn("procQty");
                return false;
            }

            /*if (ds_master.NameValue(i,"acqDt") > ed_procDt.text) {
                cfAlertMsg("자산번호 " + ds_master.NameString(i,"fixedAsetNo") + " 의 전환일자가 취득일자 이전입니다.");
                ds_master.RowPosition = i;
                gr_master.SetColumn("fixedAsetNo");
                return false;
            } */
        }
    }
    return true;
}

scwin.udc_companyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.udc_companyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_clear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

scwin.sbm_search_submiterror = function (e) {
    $c.gus.cfShowError(sbm_search);
};

scwin.sbm_master_submiterror = function (e) {
    $c.gus.cfShowError(sbm_master);
};

scwin.sbm_master_submitdone = function (e) {
    if (ds_slipNo.getCellData(0, "slipNo") != "") {
        $c.gus.cfShowSlipInfo(ds_slipNo.getCellData(0, "slipNo"));
    }
    scwin.f_Retrieve();
};

scwin.sbm_search_submitdone = async function (e) {
    // $c.gus.cfHideDSWaitMsg(gr_master);
    var rowCnt = ds_master.getRowCount();
    // cfShowTotalRows(totalRows, rowCnt);
    ed_totalRow.setValue(rowCnt);
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);

    } else {
        for (let i = 0; i < rowCnt; i++) {
            if (ds_master.getCellData(i, "stockAsetYn") == "Y") {
                gr_master.setReadOnly("cell", i, "procYn", true);
            } else {
                gr_master.setReadOnly("cell", i, "procYn", false);
            }
        }
    }
};

scwin.f_openPopUp = function (check) {
    // var rtnList = new Array();
    var param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",0";
    udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc, ed_srchAcctDeptCd.getValue(), ed_srchAcctDeptNm.getValue(), check, null
        , null, null, null, param, null
        , null, null, null, null, "T"
        , null, null
    );
};

/**
 * 귀속부서코드 팝업 callBack
 */
scwin.udc_acctDeptCd_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ed_srchAcctDeptCd.setValue(ret[0]);        // 귀속부서코드
        ed_srchAcctDeptNm.setValue(ret[1]);        // 귀속부서명
        ed_srchAcctDeptCd.options.hidVal = ret[0];         // 히든값
    } else {
        ed_srchAcctDeptCd.setValue("");            // 귀속부서코드
        ed_srchAcctDeptNm.setValue("");            // 귀속부서명
        ed_srchAcctDeptCd.options.hidVal = "";           // 히든값
    }
};

scwin.udc_acctDeptCd_onclickEvent = function (e) {
    scwin.f_openPopUp('T');
};

scwin.udc_acctDeptCd_onviewchangeCodeEvent = function (info) {
    ed_srchAcctDeptNm.setValue("");
    if (!$c.gus.cfIsNull(ed_srchAcctDeptCd.getValue())) {
        scwin.f_openPopUp("T");
    }
};

scwin.deprCompleteFormat = function (value) {
    if (value == "") {
        return "";
    } else if (value == "1") {
        return "완료";
    } else {
        return "진행";
    }
}

scwin.ds_master_oncelldatachange = function (info) {

    var row = info.rowIndex;
    var colid = info.colID;

    if (colid == "procYn") {
        if (ds_master.getCellData(row, "procYn") == 0) {
            ds_master.setCellData(row, "procQty", "0");
            // gr_master.ColumnProp("procQty","Edit") = "none";
        } else {
            ds_master.setCellData(row, "procQty", ds_master.getCellData(row, "qty"));
            // gr_master.ColumnProp("procQty","Edit") = "RealNumeric";
        }
    }

    // 수량 변경시
    if (colid == "procQty") {

        ds_master.setCellData(row, "procRate", Number(ds_master.getCellData(row, "procQty")) / Number(ds_master.getCellData(row, "qty")) * 100);

        var procRate = Number(ds_master.getCellData(row, "procRate")) / 100;

        ds_master.setCellData(row, "procAcqAmt", Math.round(Number(ds_master.getCellData(row, "acqAmt")) * (procRate)));

        ds_master.setCellData(row, "procBefYyProvAmt", Math.round(Number(ds_master.getCellData(row, "befYyProvAmt")) * (procRate)));
        ds_master.setCellData(row, "procThisYyProvAmt", Math.round(Number(ds_master.getCellData(row, "thisYyProvAmt")) * (procRate)));
        ds_master.setCellData(row, "procBookAmt", Number(ds_master.getCellData(row, "procAcqAmt"))
            - (Number(ds_master.getCellData(row, "procBefYyProvAmt")) + Number(ds_master.getCellData(row, "procThisYyProvAmt"))));
    }
};
